// Lee mensaje de Telegram y genera {chatId, query, rawText}
const u = $json;
const msg = u.message || {};

const chatId = msg.chat?.id ?? null;
const rawText = (msg.text ?? "").toString().trim();

// normaliza: si escriben "buscar xxx" o "/buscar xxx"
let query = rawText.replace(/^\/?buscar\s+/i, "").trim().toLowerCase();

return [{json:{chatId, rawText, query}}];

// Decide: si query coincide EXACTO con categoría -> modo category
// si no -> modo search (contiene). Inicializa loop.

const BASE = "https://books.toscrape.com/";

const norm = s =>
  (s ?? "")
    .toString()
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase();

const chatId = $json.chatId ?? null;
const rawText = ($json.rawText ?? "").toString().trim();
const query = norm($json.query ?? rawText);

const names = Array.isArray($json.category_names) ? $json.category_names : [];
const hrefs = Array.isArray($json.category_hrefs) ? $json.category_hrefs : [];

const categories = names.map((n, i) => {

  let href = (hrefs[i] ?? "").toString().trim();

  // limpiar ../
  href = href.replace(/^(\.\.\/)+/, "");

  return {
    name: (n ?? "").toString().trim(),
    key: norm(n),
    url: BASE + href
  };

});

const match = categories.find(c => c.key === query) || null;
const mode = match ? "category" : "search";

let currentUrl;

if (mode === "category") {

  currentUrl = match.url;

} else {

  currentUrl = BASE + "catalogue/page-1.html";

}

// seguridad extra
if (!currentUrl.startsWith("http")) {
  currentUrl = BASE;
}

return [{
  json: {
    chatId,
    rawText,
    query,
    mode,
    category: match ? match.name : "",
    currentUrl,
    results: [],
    pageCount: 0,
    maxPages: 50
  }
}];

// Accumulate & Next
// - Acumula resultados hasta 10
// - Si mode=category: NO filtra (top 10 de esa categoría)
// - Si mode=search: filtra por "contiene" (incluye letra sola como 'a')
// - Calcula nextUrl y hasNext (BOOLEAN)
// - Mantiene currentUrl siempre válido
// - Links absolutos que sí abren

const BASE = "https://books.toscrape.com/";

const item = $json;

// Datos del HTML (Parse Books)
const titles = Array.isArray(item.titles) ? item.titles : [];
const hrefs  = Array.isArray(item.hrefs) ? item.hrefs : [];
const prices = Array.isArray(item.prices) ? item.prices : [];
const nextRel = (item.nextRel ?? "").toString().trim();

// Estado
const mode = (item.mode ?? "search").toString(); // "category" | "search"
const query = (item.query ?? "").toString().trim().toLowerCase();

let currentUrl = (item.currentUrl ?? "").toString().trim();
if (!currentUrl.startsWith("http")) currentUrl = BASE;

const pageCount = Number(item.pageCount ?? 0);
const maxPages  = Number(item.maxPages ?? 50);

const prevResults = Array.isArray(item.results) ? item.results : [];

// Helpers URL (SIN new URL, para que no falle en tu n8n)
function cleanRel(rel) {
  return (rel ?? "").toString().trim().replace(/^(\.\.\/)+/, "").replace(/^\/+/, "");
}

function absUrl(rel, baseUrl) {
  const r = cleanRel(rel);
  if (!r) return "";
  // si ya es absoluta
  if (r.startsWith("http://") || r.startsWith("https://")) return r;

  // baseUrl puede ser: https://books.toscrape.com/catalogue/page-2.html
  // necesitamos: https://books.toscrape.com/ + r (si r es catalogue/...)
  // o https://books.toscrape.com/catalogue/ + r (si r es a-light... dentro de catalogue/)
  if (r.startsWith("catalogue/") || r.startsWith("media/")) {
    return BASE + r;
  }

  // Si estamos en catalogue/..., y el href viene como "a-book_1/index.html"
  // lo colgamos de /catalogue/
  if (baseUrl.includes("/catalogue/")) {
    return BASE + "catalogue/" + r;
  }

  // fallback
  return BASE + r;
}

// Filtro
function titleMatches(t) {
  if (mode !== "search") return true;   // category -> no filtra
  if (!query) return true;              // si escriben vacío, devuelve lo que venga
  const title = (t ?? "").toString().toLowerCase();
  return title.includes(query);
}

// Construir libros en esta página
const pageBooks = [];
for (let i = 0; i < titles.length; i++) {
  const title = titles[i];
  if (!titleMatches(title)) continue;

  pageBooks.push({
    title,
    price: prices[i] ?? "",
    link: absUrl(hrefs[i], currentUrl),
  });
}

// Acumular
const merged = [...prevResults, ...pageBooks];
const results10 = merged.slice(0, 10);

// Decidir si seguimos
let hasNext = false;   // ✅ BOOLEAN real
let nextUrl = "";

// Para categoría: igual usamos paginación si aún no hay 10 y existe next
// Para search: igual
const canGoNext =
  results10.length < 10 &&
  (pageCount + 1) < maxPages &&
  !!nextRel;

if (canGoNext) {
  nextUrl = absUrl(nextRel, currentUrl);

  if (nextUrl && nextUrl.startsWith("http")) {
    hasNext = true;          // ✅ BOOLEAN real
    currentUrl = nextUrl;    // preparar siguiente vuelta
  } else {
    hasNext = false;
  }
} else {
  hasNext = false;
}

// DEVUELVE el estado para el IF/Loop
return [
  {
    json: {
      ...item,

      results: results10,
      count: results10.length,

      pageCount: pageCount + 1,
      currentUrl,
      nextUrl,

      hasNext, // ✅ boolean real, NO string

      // debug (opcional)
      debug_titles_on_page: titles.length,
      debug_added_this_page: pageBooks.length,
      debug_total_after_merge: merged.length,
      debug_nextRel: nextRel,
    },
  },
];

// Devuelve {chatId, text} para Telegram
const chatId = $json.chatId ?? null;
const mode = ($json.mode ?? "search").toString();
const query = ($json.query ?? "").toString();
const category = ($json.category ?? "").toString();

const results = Array.isArray($json.results) ? $json.results : [];

let header = mode === "category"
  ? `📚 Categoría: "${category}"\n✅ Top ${results.length}:`
  : `🔎 Buscaste: "${query}"\n✅ Top ${results.length}:`;

let body = results.length
  ? results.map((r,i)=>`${i+1}) ${r.title}\n💰 ${r.price}\n🔗 ${r.link}`).join("\n\n")
  : `❌ No encontré 10 coincidencias.\n👉 Prueba otra palabra o una categoría exacta (travel, mystery, crime, etc.).`;

let text = `${header}\n\n${body}`;
if (text.length > 3800) text = text.slice(0,3800) + "\n\n...(recortado)";

return [{json:{chatId, text}}];
